#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        if (X < Y) {
            printf("FIRST\n");
        } else if (X > Y) {
            printf("SECOND\n");
        } else {
            printf("ANY\n");
        }
    }
    return 0;
}

